"use client";

/* ════════════════════════════════════════════════════════════════════════
   InboundTimeline — Operations Tier-1 instrument.

   Question it answers: "What's landing in the next two weeks and is any of
   it at risk?" — a single look at every open PO on one timeline, with the
   overdue zone red, the today marker pulsing compass-blue, and shipment
   tickets colored by status. Click a ticket → opens shipment detail in the
   Bridge / Receiving.

   Built to the Magellan Chart Standard:
     - §2.1 viewBox === pixel width via useChartSize → axis text is true-px
     - §2.2 typed Shipment[] data, sampleInboundData exported, no hardcoded numbers
     - §2.3 headline/verdict/total readable WITHOUT hovering
     - §2.5 four states: ready / loading / empty / error
     - §2.6 reduced-motion safe
     - §2.8 one truth: are we on schedule for restock?
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useMemo, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export type ShipmentStatus = "ontrack" | "partial" | "late";
export type ChartState = "ready" | "loading" | "empty" | "error";

export interface Shipment {
  po: string;
  supplier: string;
  item: string;
  /** Value in store currency units */
  value: number;
  /** Offset in days from today; negative = overdue */
  day: number;
  status: ShipmentStatus;
  received: number;
  ordered: number;
  /** Human-readable timing label */
  when: string;
}

export interface InboundTimelineProps {
  /** Omit to use sample data. */
  data?: Shipment[];
  state?: ChartState;
  /** Day range; default -5..+14 (5 days back, 2 weeks ahead). */
  dayMin?: number;
  dayMax?: number;
  /** Fires when a shipment ticket is clicked — wire to Bridge / Receiving handoff. */
  onShipmentClick?: (s: Shipment) => void;
}

/** Sample data, typed identically to the real shape. */
export const sampleInboundData: Shipment[] = [
  { po: "PO-1043", supplier: "PrintPro", item: "Gift Wrap (assorted)", value: 62000, day: -3, status: "late", received: 0, ordered: 500, when: "3 days overdue" },
  { po: "PO-1041", supplier: "TechParts OEM", item: "Screen Protector Pro", value: 5520, day: 2, status: "ontrack", received: 0, ordered: 240, when: "in 2 days" },
  { po: "PO-1038", supplier: "Lin Textiles", item: "Linen Throw Pillow", value: 27800, day: 5, status: "partial", received: 60, ordered: 150, when: "in 5 days" },
  { po: "PO-1047", supplier: "TechParts OEM", item: "Wireless Charger Pad", value: 33260, day: 6, status: "ontrack", received: 0, ordered: 120, when: "in 6 days" },
  { po: "PO-1035", supplier: "PackCo", item: "Cables (bulk)", value: 9600, day: 9, status: "ontrack", received: 0, ordered: 150, when: "in 9 days" },
];

const fmtK = (v: number) =>
  "$" + (Math.abs(v) >= 1000 ? Math.round(v / 1000) + "K" : Math.round(v).toString());

const fmtFull = (v: number) => "$" + Math.round(v).toLocaleString();

const STATUS_LABEL: Record<ShipmentStatus, string> = {
  ontrack: "On track",
  partial: "Partial",
  late: "Overdue",
};

const ROW_H = 62;
const PLOT_PAD_TOP = 16;
const PLOT_PAD_BOTTOM = 30;

export function InboundTimeline({
  data = sampleInboundData,
  state = "ready",
  dayMin = -5,
  dayMax = 14,
  onShipmentClick,
}: InboundTimelineProps) {
  const { ref: plotRef, width: plotW } = useChartSize({ min: 600, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);

  // Escape closes the drawer
  useEffect(() => {
    if (selectedIdx === null) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") setSelectedIdx(null);
    };
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [selectedIdx]);

  // Compute headline + verdict from data
  const { total, late, partial, atRisk, sortedShipments, sortedByDay, suppliers } = useMemo(() => {
    const total = data.reduce((sum, s) => sum + s.value, 0);
    const late = data.filter((s) => s.status === "late");
    const partial = data.filter((s) => s.status === "partial");
    const atRisk =
      late.reduce((a, s) => a + s.value, 0) + partial.reduce((a, s) => a + s.value, 0);
    const sortedShipments = [...data].sort((a, b) => a.day - b.day);
    const sortedByDay = [...data].sort((a, b) => a.day - b.day);
    const suppliers = Array.from(new Set(data.map((s) => s.supplier)));
    return { total, late, partial, atRisk, sortedShipments, sortedByDay, suppliers };
  }, [data]);

  const span = dayMax - dayMin;
  const xPct = (day: number) => ((day - dayMin) / span) * 100;
  const todayPct = xPct(0);

  // Argument string derived from real data
  const argument = useMemo(() => {
    if (late.length === 0 && partial.length === 0) {
      return `All ${data.length} shipments are tracking to land on time — <b>${fmtK(total)}</b> of inventory arriving over the next two weeks with nothing overdue. No action needed.`;
    }
    const top = late[0] ?? partial[0];
    const tail = partial.length > 0 && late.length > 0 ? "; one delivery is also partial" : "";
    const verb = late.length === 0 ? "is at risk" : "is overdue";
    const action = late.length === 0 ? "follow up to confirm timing" : `Chase ${top.supplier} before it gaps the restock window`;
    return `<b>${late.length || partial.length} shipment${(late.length || partial.length) > 1 ? "s" : ""} ${verb}</b> — ${top.supplier}'s ${fmtK(top.value)} ${top.when}. Of your ${fmtK(total)} inbound, <b>${fmtK(atRisk)}</b> is at risk this week${tail}. ${action}.`;
  }, [data, late, partial, total, atRisk]);

  const pillState: "attention" | "ontrack" = late.length > 0 ? "attention" : "ontrack";
  const pillText = late.length > 0 ? `${late.length} overdue` : "All on track";

  // ───────────────────── States ─────────────────────
  if (state !== "ready" || data.length === 0) {
    const message =
      state === "loading"
        ? "Loading inbound shipments…"
        : state === "error"
          ? "Couldn't load inbound timeline. Check the connection."
          : "No open purchase orders — when a PO is created it will appear here.";
    return (
      <div className="ov-tl-wrap">
        <div className="ov-timeline">
          <div className={`ov-state ov-state--${state === "ready" ? "empty" : state}`}>
            <span className="ov-state-mk" />
            <p>{message}</p>
          </div>
        </div>
      </div>
    );
  }

  // ───────────────────── Ready ─────────────────────
  const plotH = sortedShipments.length * ROW_H + PLOT_PAD_BOTTOM;

  const isDrawerOpen = selectedIdx !== null;
  const selectedShipment = selectedIdx !== null ? sortedShipments[selectedIdx] : null;

  return (
    <div className={`ov-tl-wrap${isDrawerOpen ? " open" : ""}`}>
      <div className={`ov-timeline${isDrawerOpen ? " open" : ""}`}>
        {/* Header */}
        <div className="ov-tl-head">
          <div className="ov-tl-headline">
            <div className="k">Inbound value landing · next 14 days</div>
            <div className="big">
              {fmtK(total)} <span className="unit">landed</span>
            </div>
            <div className="sub">
              {data.length} shipments across {suppliers.length} suppliers
            </div>
          </div>
          <div className="ov-tl-verdict">
            <div className={`ov-vpill ${pillState}`}>
              <span className="dot" />
              <span className="t">{pillText}</span>
            </div>
            <div className="ov-tl-legend">
              <span className="ov-tl-leg">
                <span className="sw" style={{ background: "#42679f" }} />
                On track
              </span>
              <span className="ov-tl-leg">
                <span className="sw" style={{ background: "#b3851f" }} />
                Partial
              </span>
              <span className="ov-tl-leg">
                <span className="sw" style={{ background: "#c93b3b" }} />
                Overdue
              </span>
            </div>
          </div>
        </div>

        {/* Plot */}
        <div className="ov-tl-inner">
          <div className="ov-tl-plot" ref={plotRef} style={{ minHeight: plotH }}>
            {/* SVG background layer — overdue band, gridlines, today line */}
            <svg
              viewBox={`0 0 ${plotW} ${plotH}`}
              style={{
                position: "absolute",
                inset: 0,
                width: "100%",
                height: plotH,
                pointerEvents: "none",
                zIndex: 0,
              }}
            >
              {/* Overdue band (left of today) */}
              <rect
                x={0}
                y={0}
                width={(todayPct / 100) * plotW}
                height={plotH - PLOT_PAD_BOTTOM}
                fill="rgba(207,68,68,0.045)"
                rx={8}
              />
              <line
                x1={(todayPct / 100) * plotW}
                y1={0}
                x2={(todayPct / 100) * plotW}
                y2={plotH - PLOT_PAD_BOTTOM}
                stroke="rgba(207,68,68,0.35)"
                strokeWidth={1.5}
                strokeDasharray="4 4"
              />
              {/* Gridlines at +3, +7, +10, +14 */}
              {[3, 7, 10, 14].map((d) => (
                <line
                  key={d}
                  x1={(xPct(d) / 100) * plotW}
                  y1={0}
                  x2={(xPct(d) / 100) * plotW}
                  y2={plotH - PLOT_PAD_BOTTOM}
                  stroke="rgba(0,0,0,0.07)"
                  strokeWidth={0.5}
                  strokeDasharray="2 4"
                />
              ))}
              {/* Today line — compass blue */}
              <line
                x1={(todayPct / 100) * plotW}
                y1={-6}
                x2={(todayPct / 100) * plotW}
                y2={plotH - PLOT_PAD_BOTTOM}
                stroke="var(--compass)"
                strokeWidth={2}
              />
              {/* Today pulsing beacon at the marker top */}
              <circle cx={(todayPct / 100) * plotW} cy={6} r={5} fill="var(--compass)">
                {!reduce && (
                  <>
                    <animate attributeName="r" values="5;14" dur="2.2s" repeatCount="indefinite" />
                    <animate attributeName="opacity" values="0.85;0" dur="2.2s" repeatCount="indefinite" />
                  </>
                )}
              </circle>
              <circle cx={(todayPct / 100) * plotW} cy={6} r={3} fill="var(--compass)" />
            </svg>

            {/* "Overdue" label */}
            <div className="ov-tl-overdue-l" style={{ left: 14, top: 8 }}>
              Overdue
            </div>
            {/* "Today" label */}
            <div
              className="ov-tl-today-l"
              style={{ left: `calc(${todayPct}% + 10px)`, top: -3 }}
            >
              Today
            </div>

            {/* Shipment tickets — absolute positioned by day */}
            <div className="ov-tl-rows" style={{ position: "relative", zIndex: 1 }}>
              {sortedShipments.map((s, i) => {
                const left = xPct(s.day);
                const anchorRight = left > 72;
                const sub =
                  s.status === "partial"
                    ? `${s.po} · ${s.received}/${s.ordered} received`
                    : `${s.po} · ${s.when}`;
                const isSelected = selectedIdx === i;
                return (
                  <div key={s.po} className="ov-tl-row">
                    <button
                      className={`ov-tk ${s.status}${isSelected ? " sel" : ""}`}
                      style={{
                        ...(anchorRight
                          ? { right: `${Math.max(0, 100 - left)}%` }
                          : { left: `${left}%` }),
                        opacity: reduce ? 1 : 0,
                        animation: reduce
                          ? undefined
                          : `ov-tk-in .5s cubic-bezier(.4,.1,.2,1) ${0.1 + i * 0.08}s forwards`,
                      }}
                      onClick={() => {
                        const next = selectedIdx === i ? null : i;
                        setSelectedIdx(next);
                        if (next !== null) onShipmentClick?.(s);
                      }}
                      aria-label={`${s.supplier} ${s.po}, ${fmtFull(s.value)}, ${s.when}`}
                      aria-expanded={isSelected}
                    >
                      <span className="tk-amt">{fmtK(s.value)}</span>
                      <span className="tk-sub">{sub}</span>
                    </button>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Axis */}
          <div className="ov-tl-axis">
            <span className="ov-tl-axis-l" style={{ left: `${todayPct}%` }}>
              Today
            </span>
            <span className="ov-tl-axis-l" style={{ left: `${xPct(3)}%` }}>
              +3 days
            </span>
            <span className="ov-tl-axis-l" style={{ left: `${xPct(7)}%` }}>
              +1 week
            </span>
            <span className="ov-tl-axis-l" style={{ left: `${xPct(10)}%` }}>
              +10 days
            </span>
            <span className="ov-tl-axis-l" style={{ left: `${xPct(14)}%` }}>
              +2 weeks
            </span>
          </div>
        </div>

        {/* Argument line — derived from data */}
        <div className={`ov-tl-arg ${pillState}`}>
          <span className="mk" />
          <p dangerouslySetInnerHTML={{ __html: argument }} />
        </div>
      </div>

      {/* Slide-in drawer (shown when a shipment is selected) */}
      <aside className="ov-drawer" aria-hidden={!isDrawerOpen}>
        {selectedShipment && (
          <>
            <div className="ovd-top">
              <span className={`ovd-status ${selectedShipment.status}`}>
                {STATUS_LABEL[selectedShipment.status]}
              </span>
              <button className="ovd-clear" onClick={() => setSelectedIdx(null)} aria-label="Close detail">
                close ✕
              </button>
            </div>
            <div className="ovd-sup">{selectedShipment.supplier}</div>
            <div className="ovd-po">
              {selectedShipment.po} · {selectedShipment.item}
            </div>
            <div className="ovd-val">{fmtFull(selectedShipment.value)}</div>
            <div className="ovd-val-u">shipment value · landed</div>
            <div className="ovd-rows">
              <div className="ovd-r">
                <span className="rl">Expected</span>
                <span className={`rv ${selectedShipment.status === "late" ? "late" : ""}`}>
                  {selectedShipment.when}
                </span>
              </div>
              <div className="ovd-r">
                <span className="rl">Units</span>
                <span className="rv">
                  {selectedShipment.status === "partial"
                    ? `${selectedShipment.received} of ${selectedShipment.ordered} in`
                    : `${selectedShipment.ordered} ordered`}
                </span>
              </div>
              <div className="ovd-r">
                <span className="rl">Status</span>
                <span
                  className={`rv ${
                    selectedShipment.status === "late"
                      ? "late"
                      : selectedShipment.status === "partial"
                        ? "partial"
                        : ""
                  }`}
                >
                  {STATUS_LABEL[selectedShipment.status]}
                </span>
              </div>
            </div>
            <a className="ovd-go" href="#">
              {selectedShipment.status === "late" ? "Chase in Receiving" : "Open in Receiving"} →
            </a>
          </>
        )}
      </aside>
    </div>
  );
}
