"use client";

import { useState, useEffect, useRef, useCallback } from "react";

/**
 * useChartSize — the single source of responsive chart sizing for Magellan.
 *
 * Satisfies the Responsive & Ultrawide spec, Rule 2 ("chart text is locked to TRUE pixels"):
 * reports the chart container's ACTUAL rendered pixel width so the consuming chart can set
 *   viewBox = `0 0 ${width} ${height}`
 * making 1 viewBox unit === 1 real pixel. That keeps `font-size: 13` rendering at a true 13px
 * on a laptop, a 27" iMac, and an ultrawide alike — only the drawing area widens, the type
 * never scales.
 *
 * - Measures with ResizeObserver (falls back to window resize).
 * - Debounced (~120ms) per spec.
 * - Skips re-renders on identical width (dedupe).
 * - Returns a clamped width so charts never collapse below a sane minimum.
 */

export interface ChartSize {
  /** Attach to the element whose width the SVG should fill. */
  ref: React.RefObject<HTMLDivElement | null>;
  /** Live, clamped, rounded pixel width of the container. */
  width: number;
}

export interface UseChartSizeOptions {
  /** Minimum width the chart will report (prevents collapse). Default 640. */
  min?: number;
  /** Width used before the first measurement (SSR / first paint). Default 1000. */
  fallback?: number;
  /** Debounce in ms for resize redraws. Default 120 (per spec). */
  debounceMs?: number;
}

export function useChartSize(options: UseChartSizeOptions = {}): ChartSize {
  const { min = 640, fallback = 1000, debounceMs = 120 } = options;
  const ref = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState<number>(fallback);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const measure = useCallback(() => {
    const el = ref.current;
    if (!el) return;
    const w = Math.max(min, Math.round(el.getBoundingClientRect().width || fallback));
    setWidth((prev) => (prev === w ? prev : w));
  }, [min, fallback]);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    measure();

    const schedule = () => {
      if (timer.current) clearTimeout(timer.current);
      timer.current = setTimeout(measure, debounceMs);
    };

    let ro: ResizeObserver | null = null;
    if (typeof ResizeObserver !== "undefined") {
      ro = new ResizeObserver(schedule);
      ro.observe(el);
    }
    window.addEventListener("resize", schedule);

    return () => {
      if (timer.current) clearTimeout(timer.current);
      if (ro) ro.disconnect();
      window.removeEventListener("resize", schedule);
    };
  }, [measure, debounceMs]);

  return { ref, width };
}

/** Respects the user's reduced-motion preference for one-shot draw animations. */
export function usePrefersReducedMotion(): boolean {
  const [reduced, setReduced] = useState(false);
  useEffect(() => {
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReduced(mq.matches);
    const handler = (e: MediaQueryListEvent) => setReduced(e.matches);
    mq.addEventListener?.("change", handler);
    return () => mq.removeEventListener?.("change", handler);
  }, []);
  return reduced;
}
